<?php
declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';use VP3\Installation\InstallationJobService;$admin=vp3_require_admin_permission('installations.manage');if(vp3_method()==='POST'){vp3_verify_csrf();$uuid=vp3_input('job_uuid');$service=new InstallationJobService(vp3_db());try{if(vp3_input('action')==='confirm'){$service->confirmManualStep($uuid,(int)$admin['id']);vp3_flash('success','Manual step confirmed; the job is ready to continue.');}else{$result=$service->run($uuid);vp3_flash('success',$result['job_status']==='waiting_manual'?'Installation paused for a manual provider action.':'Installation job completed.');}}catch(Throwable $e){vp3_flash('error','Installation job failed: '.$e->getMessage());}vp3_redirect('admin/installations.php');}$pageTitle='Installation Jobs';require VP3_ROOT.'/includes/admin-header.php';$rows=vp3_db()->query('SELECT ij.*,h.subdomain,p.name product_name,c.name customer_name FROM installation_jobs ij JOIN hosting_accounts h ON h.id=ij.hosting_account_id JOIN products p ON p.id=ij.product_id JOIN customers c ON c.id=h.customer_id ORDER BY ij.id DESC LIMIT 250')->fetchAll();?><h1>Installation jobs</h1><p class="helper">Simulator jobs run controlled stages. Manual-provider jobs pause at every infrastructure action until an administrator confirms that the action was completed outside VP3. No browser-controlled shell execution is used.</p><div class="table-wrap"><table class="table"><thead><tr><th>Customer</th><th>Platform</th><th>Status</th><th>Step</th><th>Progress</th><th>Version</th><th>Action</th></tr></thead><tbody><?php foreach($rows as $x):?><tr><td><?=vp3_e($x['customer_name'])?></td><td><?=vp3_e($x['subdomain'])?><br><small><?=vp3_e($x['product_name'])?></small></td><td><span class="badge <?=vp3_e($x['job_status'])?>"><?=vp3_e($x['job_status'])?></span></td><td><?=vp3_e($x['current_step'])?></td><td><?=(int)$x['progress_percent']?>%</td><td><?=vp3_e($x['requested_version'])?></td><td><?php if($x['job_status']==='waiting_manual'):?><form method="post"><?=vp3_csrf_field()?><input type="hidden" name="job_uuid" value="<?=vp3_e($x['job_uuid'])?>"><input type="hidden" name="action" value="confirm"><button class="button small">Confirm manual step</button></form><?php elseif(in_array($x['job_status'],['queued','failed'],true)):?><form method="post"><?=vp3_csrf_field()?><input type="hidden" name="job_uuid" value="<?=vp3_e($x['job_uuid'])?>"><input type="hidden" name="action" value="run"><button class="button small">Run / restart</button></form><?php endif;?></td></tr><?php endforeach;?></tbody></table></div><?php require VP3_ROOT.'/includes/admin-footer.php';?>
